B.bB=new A.ah("Dart \u2014 Exceptions (try/catch/finally)","dart","class Foo {\n  static void main(int a, int b) {\n    // Catch a built-in VM runtime error (division by zero):\n    try {\n      print('a ~/ b = ${a ~/ b}');\n    } catch (e) {\n      print('caught runtime error: $e');\n    } finally {\n      print('division done');\n    }\n\n    // Catch a user-thrown value (typed `on String`); finally always runs:\n    try {\n      if (b == 0) {\n        throw 'b must not be zero';\n      }\n      print('b is fine: $b');\n    } on String catch (msg) {\n      print('caught: $msg');\n    } finally {\n      print('check done');\n    }\n  }\n}\n","Foo","main","10, 0",!1)
B.bo=new A.ah("Java11 \u2014 Exceptions (try/catch/finally)","java11",'class Foo {\n   static public void main(int a, int b) {\n     // Catch a built-in VM runtime error (integer division by zero):\n     try {\n       print("a / b = " + (a / b));\n     } catch (Exception e) {\n       print("caught runtime error: " + e);\n     } finally {\n       print("division done");\n     }\n\n     // Catch a user-thrown value (typed); finally always runs:\n     try {\n       if (b == 0) {\n         throw "b must not be zero";\n       }\n       print("b is fine: " + b);\n     } catch (String msg) {\n       print("caught: " + msg);\n     } finally {\n       print("check done");\n     }\n   }\n}\n',"Foo","main","10, 0",!1)
